  ('cpa-moex-00871', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲出售其32年前取得之一般土地，其應納土地增值稅所適用之累進稅率結構依土地稅法規定為何？', '["20%，30%，40%", "20%，29%，38%", "20%，28%，36%", "20%，27%，34%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00872', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法第11條之1規定，下列有關擔保品之敘述，何者正確？', '["黃金按八折計算", "核准上市之有價證券按八折計算", "政府公債按面額九折計算", "銀行存款單摺按存款本利合計值計算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00873', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '104年度房屋稅繳納期間為104年5月1日至5月31日（星期日），甲104年度應納房屋稅額 1,000元，遲至104年6月3日繳納，依稅捐稽徵法規定，應加徵滯納金多少元？', '["0", "10", "20", "150"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00874', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，有關由稅捐稽徵機關依稅籍底冊或查得資料核定課徵之稅捐及其核課期間之 規定，下列敘述何者正確？', '["相關稅捐包括地價稅、土地增值稅、房屋稅、使用牌照稅及查定課徵之營業稅、娛樂稅，其核 課期間為5年", "相關稅捐包括地價稅、土地增值稅、房屋稅、使用牌照稅及查定課徵之營業稅、娛樂稅，其核 課期間為7年", "相關稅捐包括地價稅、田賦、房屋稅、使用牌照稅及查定課徵之營業稅、貨物稅，其核課期間 為5年", "相關稅捐包括地價稅、田賦、房屋稅、使用牌照稅及查定課徵之營業稅、娛樂稅，其核課期間 為5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00875', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，稅捐稽徵機關對於逃漏下列何項稅捐，而涉有犯罪嫌疑之案件，得敘明事由， 聲請當地司法機關簽發搜索票後，會同當地警察或自治人員，進入藏置帳簿、文件或證物之處所， 實施搜查？', '["地價稅", "房屋稅", "營業稅", "娛樂稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00876', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法第44條規定，營利事業違反給與或取得憑證之處罰，下列敘述何者正確？', '["依規定應給與他人憑證而未給與者，應就其未給與憑證，經查明認定之總額，處1%罰鍰，處 罰金額最高不得超過新臺幣100萬元", "依規定應自他人取得憑證而未取得者，應就其未取得憑證，經查明認定之總額，處3%罰鍰， 處罰金額最高不得超過新臺幣100萬元", "依規定應保存憑證而未保存者，應就其未保存憑證，經查明認定之總額，處5%罰鍰，處罰金 額最高不得超過新臺幣100萬元", "依規定應保存憑證而未保存者，應就其未保存憑證，處新臺幣3萬元以上6萬元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00877', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，有關遺產稅及贈與稅之繳納，下列何者之申請條件不受應納稅額30萬 元以上之限制？', '["以中華民國境內不易變價或保管之課徵標的物申請抵繳時", "以在中華民國境內之課徵標的物或納稅義務人所有易於變價及保管之實物申請一次抵繳時", "納稅義務人確有困難，不能一次繳納現金時，於納稅期間內，向該管稽徵機關申請分期繳 納時", "納稅義務人應於稽徵機關送達核定納稅通知書之日起二個月內，繳清應納稅款；必要時，於限 期內申請稽徵機關核准延期二個月時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00878', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，下列信託財產何者不課徵遺產稅或贈與稅？', '["因遺囑成立之信託，於遺囑人死亡時，其信託財產", "信託關係存續中受益人死亡時，其享有信託利益之權利未領受部分", "信託契約明定信託利益之全部或一部之受益人為非委託人", "信託關係存續中，受託人依信託本旨交付信託財產，受託人與受益人間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00879', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲於107年3月贈與其長子股票一批，時價為200萬元；同年8月，贈與其次子房屋一棟，評定標 準價格為150萬元，由次子繳納契稅3萬元。107年第2次贈與時申報之課稅贈與淨額為多少？', '["127萬元", "236萬元", "243萬元", "250萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00880', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲係職業軍人，於107年2月1日因執行職務不幸死亡，死後遺有財產，依遺產及贈與稅法規定， 於課徵遺產稅時其免稅額為多少？', '["700萬元", "1,200萬元", "1,400萬元", "2,400萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
